INSERT INTO public.recipes (id, name, slug, description, protein_id, cuisine_id, image_url, prep_time_min, cook_time_min, total_time_min, difficulty, default_servings, created_at) VALUES ('4968c641-6162-4a10-84ea-a77f1c5e969d', 'Grilled Salmon with Honey and Lemon', 'grilled-salmon-honey-lemon', 'Simple and delicious grilled salmon with honey, lemon, and mayo. Perfectly moist with a hint of sweetness and tang.', '58884c15-c5a1-4cda-a278-71e79b41332e', '5ab4e399-f3b6-4c90-8738-5d17816ae873', '/images/recipes/american-grilled-salmon.jpg', 5, 10, 15, 'Easy', 4, '2026-02-22 13:48:05.940593+00');
INSERT INTO public.recipes (id, name, slug, description, protein_id, cuisine_id, image_url, prep_time_min, cook_time_min, total_time_min, difficulty, default_servings, created_at) VALUES ('f71f1737-a61d-4156-92d4-fe9aea544aaa', 'Asian Style Ground Beef Lettuce Wraps', 'asian-beef-lettuce-wraps', 'Easy to make and even easier to gobble down. Sauteed ground beef and veggies in a tangy ginger garlic sauce with coconut aminos.', '840c7d6e-3db1-4e06-9ca8-960b41366cb2', '2864cb82-ff7a-414a-b8dd-9b863e49a85a', '/images/recipes/asian-beef-lettuce-wraps.jpg', 10, 15, 25, 'Easy', 4, '2026-02-24 02:32:35.554407+00');
INSERT INTO public.recipes (id, name, slug, description, protein_id, cuisine_id, image_url, prep_time_min, cook_time_min, total_time_min, difficulty, default_servings, created_at) VALUES ('6aa6282d-f5a5-4a8c-afcb-ada78628429d', 'Braised Beef in Wine Over Polenta', 'braised-beef-wine-polenta', 'Comfort in a bowl! Tender chuck roast braised in red wine with vegetables, served over creamy polenta. Perfect for a cozy dinner.', '840c7d6e-3db1-4e06-9ca8-960b41366cb2', 'c535a78a-f384-4bf9-9d54-7a340585c529', '/images/recipes/braised-beef-wine-polenta.jpg', 30, 175, 205, 'Hard', 4, '2026-02-24 02:42:37.775619+00');
INSERT INTO public.recipes (id, name, slug, description, protein_id, cuisine_id, image_url, prep_time_min, cook_time_min, total_time_min, difficulty, default_servings, created_at) VALUES ('140d80bb-5fc1-4763-b2c5-3bb166bc4565', 'Shrimp Fajita Bowls', 'shrimp-fajita-bowls', 'We turned shrimp fajitas into a delicious bowl! Build them with all your favorites to make them gluten-free or paleo!', '24073280-3225-43a6-b994-dea51052f07d', 'c12d3984-7938-444e-8cb9-9ea5541e3a17', '/images/recipes/shrimp-fajita-bowl-10.jpg', 10, 20, 35, 'Easy', 4, '2026-02-19 11:08:20.95077+00');
INSERT INTO public.recipes (id, name, slug, description, protein_id, cuisine_id, image_url, prep_time_min, cook_time_min, total_time_min, difficulty, default_servings, created_at) VALUES ('64eba0cd-ae28-4cae-948f-b904d9c3da9a', 'Gluten-Free Meatloaf', 'gluten-free-meatloaf', 'Just like mom used to make it with a sweet and tangy glaze topping. Juicy and tender meat packed with a flavorful seasoning mix and gluten-free breadcrumbs.', '840c7d6e-3db1-4e06-9ca8-960b41366cb2', '5ab4e399-f3b6-4c90-8738-5d17816ae873', '/images/recipes/gluten-free-meatloaf.jpg', 10, 75, 85, 'Medium', 8, '2026-02-21 23:17:15.04414+00');
INSERT INTO public.recipes (id, name, slug, description, protein_id, cuisine_id, image_url, prep_time_min, cook_time_min, total_time_min, difficulty, default_servings, created_at) VALUES ('b1b2c15b-333b-458a-9719-54ac4385b120', 'Japanese Beef Curry', 'japanese-beef-curry', 'Kare-raisu - thick, curried stew of beef, potatoes, carrots, and onions served over rice. Slightly sweet and spicy, a very common comfort dish in Japan.', '840c7d6e-3db1-4e06-9ca8-960b41366cb2', 'f5b00102-77a7-42e6-b0ab-eef9e5597d10', '/images/recipes/japanese-beef-curry.jpg', 30, 90, 120, 'Medium', 4, '2026-02-24 02:50:01.732599+00');
INSERT INTO public.recipes (id, name, slug, description, protein_id, cuisine_id, image_url, prep_time_min, cook_time_min, total_time_min, difficulty, default_servings, created_at) VALUES ('d5f5c3b5-6920-4625-9ea0-b87c531d286b', 'Mediterranean Beef and Veggie Skillet', 'mediterranean-beef-veggie-skillet', 'Quick and flavorful one-pan meal with ground beef, zucchini, and bell peppers. Seasoned with Mediterranean spices and fresh herbs. Gluten-free, dairy-free adaptable.', '840c7d6e-3db1-4e06-9ca8-960b41366cb2', '2cfb5416-abfc-4894-8c7a-c34b3675f10a', '/images/recipes/mediterranean-beef-veggie-skillet.jpg', 5, 20, 25, 'Easy', 4, '2026-02-24 03:02:29.006913+00');
INSERT INTO public.recipes (id, name, slug, description, protein_id, cuisine_id, image_url, prep_time_min, cook_time_min, total_time_min, difficulty, default_servings, created_at) VALUES ('390126fb-c313-42b4-a686-f896f7183bc1', 'Vietnamese Beef and Rice Noodle Salad', 'vietnamese-beef-noodle-salad', 'Bun Bo style salad with rice vermicelli, fresh herbs, and seasoned ground beef. Fresh, tasty, and filling with lime-fish sauce dressing.', '840c7d6e-3db1-4e06-9ca8-960b41366cb2', '323d4e24-99bf-4c7f-8254-8512b781ee4c', '/images/recipes/vietnamese-beef-noodle-salad.jpg', 15, 20, 35, 'Easy', 4, '2026-02-24 03:10:34.513973+00');
INSERT INTO public.recipes (id, name, slug, description, protein_id, cuisine_id, image_url, prep_time_min, cook_time_min, total_time_min, difficulty, default_servings, created_at) VALUES ('30d05dcd-033a-410a-97e9-05dc7d6cdc49', 'Gluten Free Chicken Tenders', 'gluten-free-chicken-tenders', 'Golden and crispy on the outside with tender chicken on the inside. Family favorite comfort food made gluten-free!', 'e93e8dd9-d381-44b7-a010-7188e8f9686b', '5ab4e399-f3b6-4c90-8738-5d17816ae873', '/images/recipes/gluten-free-chicken-tenders.jpg', 15, 20, 35, 'Medium', 4, '2026-02-24 11:11:34.713003+00');
INSERT INTO public.recipes (id, name, slug, description, protein_id, cuisine_id, image_url, prep_time_min, cook_time_min, total_time_min, difficulty, default_servings, created_at) VALUES ('c59717d9-8e44-4e2e-92f3-111a19c950cc', 'Baked Beef Curry', 'baked-beef-curry', 'An incredible, flavoursome baked beef curry with fragrant spices, coconut milk, tomato and fresh chilli. Enjoy with gluten-free naan or rice.', '840c7d6e-3db1-4e06-9ca8-960b41366cb2', '3f3430d5-d417-4f7f-865d-ddd17a1454a9', '/images/beef-curry.jpeg', 10, 210, 220, 'Medium', 4, '2026-02-25 00:03:12.046611+00');
